static int
do_count(char *input_files[], const int nfiles,
    const bool char_flag, const bool word_flag,
    const bool line_flag, const bool test_flag)
{
    int error_flag = 0;
    int valid_count = 0;
    struct counts total = {0, 0, 0};

    (void)test_flag;

    /* Allocate storage for valid file results. */
    struct counts *results = malloc(nfiles * sizeof(struct counts));
    char **names = malloc(nfiles * sizeof(char *));
    if (results == NULL || names == NULL) {
        free(results);
        free(names);
        print_counts(stdout, &total, "total", true, true, true);
        return 1;
    }

    /* Process each file in input order. */
    for (int i = 0; i < nfiles; i++) {
        FILE *fp;
        long chars = 0, words = 0, lines = 0;
        bool in_word = false;
        int ch;

        fp = fopen(input_files[i], "r");
        if (fp == NULL) {
            app_error_fmt("cannot open file '%s'", input_files[i]);
            error_flag = 1;
            continue;
        }

        while ((ch = fgetc(fp)) != EOF) {
            chars++;
            if (ch == '\n')
                lines++;
            if (isspace(ch)) {
                in_word = false;
            } else {
                if (!in_word) {
                    words++;
                    in_word = true;
                }
            }
        }

        if (ferror(fp)) {
            app_error_fmt("cannot read file '%s'", input_files[i]);
            error_flag = 1;
            fclose(fp);
            continue;
        }

        fclose(fp);

        results[valid_count].chars = chars;
        results[valid_count].words = words;
        results[valid_count].lines = lines;
        names[valid_count] = input_files[i];
        valid_count++;
    }

    /* Sort results by filename (ASCIIbetical order). */
    for (int i = 1; i < valid_count; i++) {
        char *key_name = names[i];
        struct counts key_cnts = results[i];
        int j = i - 1;
        while (j >= 0 && strcmp(names[j], key_name) > 0) {
            names[j + 1] = names[j];
            results[j + 1] = results[j];
            j--;
        }
        names[j + 1] = key_name;
        results[j + 1] = key_cnts;
    }

    /* Print individual results and accumulate totals. */
    for (int i = 0; i < valid_count; i++) {
        print_counts(stdout, &results[i], names[i],
            char_flag, word_flag, line_flag);
        if (char_flag)
            total.chars += results[i].chars;
        if (word_flag)
            total.words += results[i].words;
        if (line_flag)
            total.lines += results[i].lines;
    }

    /* Print totals (always print all three counts). */
    print_counts(stdout, &total, "total", true, true, true);

    free(results);
    free(names);

    return error_flag;
}

